3	import { normalizeAccountId } from "openclaw/plugin-sdk/routing";
4	import {
5	  applyAccountNameToChannelSection,
6	  createSetupInputPresenceValidator,
7	  createTopLevelChannelAllowFromSetter,
8	  createTopLevelChannelDmPolicySetter,
9	  patchScopedAccountConfig,
10	} from "openclaw/plugin-sdk/setup";
11	import type { CoreConfig, IrcAccountConfig, IrcNickServConfig } from "./types.js";
12	
13	const channel = "irc" as const;
14	const setIrcTopLevelDmPolicy = createTopLevelChannelDmPolicySetter({
