import { randomUUID } from "node:crypto";
import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { isBoardTarget } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

export function resolvePulseBoardInboundTarget(params: {
  target: string;
  senderUsername: string;
}): {
  isGroup: boolean;
  target: string;
  rawTarget: string;
} {
  const rawTarget = params.target;
  const isGroup = isBoardTarget(rawTarget);
  if (isGroup) {
    return { isGroup: true, target: rawTarget, rawTarget };
  }
  const senderUsername = params.senderUsername.trim();
  return { isGroup: false, target: senderUsername || rawTarget, rawTarget };
}

export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl, botUsername, and apiKey in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let aborted = false;

  // In a real implementation, this would open a WebSocket or long-poll
  // connection to the PulseBoard API to receive real-time messages.
  // Example: ws://${account.apiUrl}/api/v1/stream?token=${account.apiKey}
  //
  // The connection would emit events like:
  //   { type: "message", board: "~general", sender: "alice", text: "hello" }
  //   { type: "dm", sender: "bob", text: "hi there" }
  //
  // For each event, we would construct a PulseBoardInboundMessage and
  // pass it to handlePulseBoardInbound.

  const handleIncomingEvent = async (event: {
    type: "board_message" | "direct_message";
    target: string;
    senderUsername: string;
    senderDisplayName?: string;
    text: string;
  }) => {
    if (aborted) {
      return;
    }

    if (event.senderUsername.toLowerCase() === account.botUsername.toLowerCase()) {
      return;
    }

    const inboundTarget = resolvePulseBoardInboundTarget({
      target: event.target,
      senderUsername: event.senderUsername,
    });
    const message: PulseBoardInboundMessage = {
      messageId: randomUUID(),
      target: inboundTarget.target,
      rawTarget: inboundTarget.rawTarget,
      senderUsername: event.senderUsername,
      senderDisplayName: event.senderDisplayName,
      text: event.text,
      timestamp: Date.now(),
      isGroup: inboundTarget.isGroup,
    };

    core.channel.activity.record({
      channel: "pulseboard",
      accountId: account.accountId,
      direction: "inbound",
      at: message.timestamp,
    });

    if (opts.onMessage) {
      await opts.onMessage(message);
      return;
    }

    await handlePulseBoardInbound({
      message,
      account,
      config: cfg,
      runtime,
      connectedBotUsername: account.botUsername,
      sendReply: async (target, text) => {
        // In a real implementation, send via PulseBoard API here.
        opts.statusSink?.({ lastOutboundAt: Date.now() });
        core.channel.activity.record({
          channel: "pulseboard",
          accountId: account.accountId,
          direction: "outbound",
        });
      },
      statusSink: opts.statusSink,
    });
  };

  // Register abort handler.
  opts.abortSignal?.addEventListener("abort", () => {
    aborted = true;
  });

  logger.info(
    `[${account.accountId}] connected to PulseBoard at ${account.apiUrl} as ${account.botUsername}`,
  );

  // Expose handleIncomingEvent for testing/integration.
  void handleIncomingEvent;

  return {
    stop: () => {
      aborted = true;
    },
  };
}

