  });

  logger.info(
    `[${account.accountId}] connected to PulseBoard at ${account.apiUrl} as ${account.botUsername}`,
  );

  // Expose handleIncomingEvent for testing/integration.
  void handleIncomingEvent;

  return {
    stop: () => {
      aborted = true;
    },
  };
}

